// instrumentedHandler wraps an HTTP handler with per-user metrics tracking
func instrumentedHandler(endpoint string, handler http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		userID := r.Header.Get("X-User-ID")
		if userID == "" {
			userID = r.URL.Query().Get("user_id")
		}
		if userID == "" {
			userID = "anonymous"
		}

		method := r.Method

		// Track active requests
		activeRequests.WithLabelValues(userID).Inc()
		defer activeRequests.WithLabelValues(userID).Dec()

		// Track request size
		if r.ContentLength > 0 {
			httpRequestSize.WithLabelValues(userID, method, endpoint).Observe(float64(r.ContentLength))
		}

		// Time the request
		start := time.Now()

		// Use a response writer wrapper to capture status code and response size
		rw := &responseWriter{ResponseWriter: w, statusCode: http.StatusOK}

		handler(rw, r)

		duration := time.Since(start).Seconds()
		statusCode := fmt.Sprintf("%d", rw.statusCode)

		// Record metrics
		httpRequestsTotal.WithLabelValues(userID, method, endpoint, statusCode).Inc()
		httpRequestDuration.WithLabelValues(userID, method, endpoint).Observe(duration)
		httpResponseSize.WithLabelValues(userID, endpoint).Observe(float64(rw.bytesWritten))

		// Track errors
		if rw.statusCode >= 400 {
			errorType := "client_error"
			if rw.statusCode >= 500 {
				errorType = "server_error"
			}
			httpErrorsTotal.WithLabelValues(userID, endpoint, errorType).Inc()
		}
	}
}

// responseWriter wraps http.ResponseWriter to capture status code and bytes written
type responseWriter struct {
	http.ResponseWriter
	statusCode   int
	bytesWritten int
}

func (rw *responseWriter) WriteHeader(code int) {
	rw.statusCode = code
	rw.ResponseWriter.WriteHeader(code)
}

func (rw *responseWriter) Write(b []byte) (int, error) {
	n, err := rw.ResponseWriter.Write(b)
	rw.bytesWritten += n
	return n, err
}

