// simulateTraffic generates synthetic traffic for demonstration
func simulateTraffic() {
	users := []string{"user-001", "user-002", "user-003", "user-004", "user-005",
		"user-006", "user-007", "user-008", "user-009", "user-010"}
	endpoints := []string{"/api", "/search", "/upload"}
	features := []string{"dashboard", "export", "analytics", "notifications", "reports"}
	versions := []string{"v1", "v2", "v3"}
	plans := []string{"free", "pro", "enterprise"}

	client := &http.Client{Timeout: 5 * time.Second}

	for {
		userID := users[rand.Intn(len(users))]
		endpoint := endpoints[rand.Intn(len(endpoints))]
		feature := features[rand.Intn(len(features))]
		version := versions[rand.Intn(len(versions))]
		plan := plans[rand.Intn(len(plans))]

		url := fmt.Sprintf("http://localhost:8080%s?user_id=%s&feature=%s&version=%s&plan=%s",
			endpoint, userID, feature, version, plan)

		req, err := http.NewRequest("GET", url, nil)
		if err != nil {
			continue
		}
		req.Header.Set("X-User-ID", userID)

		resp, err := client.Do(req)
		if err != nil {
			// Server might not be ready yet
			time.Sleep(time.Second)
			continue
		}
		resp.Body.Close()

		// Random delay between requests
		time.Sleep(time.Duration(rand.Intn(500)+100) * time.Millisecond)
	}
}

